import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

// Import ESAPI library
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSSecureCode {

    public void secureMethod(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Encode user input using ESAPI HTML entity encoding
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedInput = codec.encode(userInput);

        // Output the properly encoded user input to the response
        response.getWriter().println("<p>User input: " + encodedInput + "</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
